import { ReportExport } from "@/components/report-export";
import { EmptyState, PageHeading, ProgressBar, SectionCard, StatusBadge } from "@/components/shared";
import { requireUser } from "@/lib/auth";
import { getReportData } from "@/lib/data";
import { formatTanggalPanjang } from "@/lib/utils";
import { FileBarChart, ShieldCheck } from "lucide-react";

export default async function ReportPage() {
  const user = await requireUser();
  const data = await getReportData(user);
  const rows = data.overview.filter((item): item is NonNullable<typeof item> => item !== null);
  const exportRows = rows.map((row) => ({ nama: row.name, nis: row.nis, halaqah: row.halaqahName ?? "Belum ada halaqah", capaian: row.progress.percentage, nilai: row.averageScore, perluPenguatan: row.weakCount }));
  return <><PageHeading eyebrow="Dokumentasi Perkembangan" title="Laporan Mutabaah" description="Rekap capaian hafalan dan kualitas setoran berdasarkan data yang tercatat pada sistem. Gunakan cetak browser untuk menyimpan dokumen sebagai PDF." action={<ReportExport rows={exportRows}/>}/><div className="mb-5 flex items-center gap-3 rounded-2xl border border-emerald-100 bg-emerald-50 px-4 py-3 text-sm text-emerald-900"><FileBarChart size={19}/><p><b>Periode ringkasan:</b> seluruh data setoran yang tersedia sampai {formatTanggalPanjang(new Date())}.</p></div><SectionCard title="Rekap per santri" subtitle={`${rows.length} santri dalam cakupan akses Anda`} action={<span className="inline-flex items-center gap-1 text-[11px] font-bold text-emerald-700"><ShieldCheck size={14}/>Data sesuai peran</span>}><div className="overflow-x-auto"><table className="w-full min-w-[760px] text-left"><thead><tr className="border-b border-slate-100 text-[10px] uppercase tracking-wider text-slate-400"><th className="px-5 py-3">Santri</th><th className="px-4 py-3">Halaqah</th><th className="px-4 py-3">Capaian hafalan</th><th className="px-4 py-3">Nilai rata-rata</th><th className="px-4 py-3">Perlu penguatan</th><th className="px-5 py-3">Status ringkas</th></tr></thead><tbody>{rows.map((row) => <tr className="border-b border-slate-50 last:border-0" key={row.id}><td className="px-5 py-4"><p className="text-sm font-bold text-slate-800">{row.name}</p><p className="mt-0.5 text-xs text-slate-500">{row.nis}</p></td><td className="px-4 py-4 text-sm text-slate-600">{row.halaqahName ?? "—"}</td><td className="px-4 py-4"><div className="w-40"><ProgressBar value={row.progress.percentage}/></div></td><td className="px-4 py-4 text-sm font-bold text-emerald-700">{row.averageScore || "—"}</td><td className="px-4 py-4 text-sm font-bold text-amber-700">{row.weakCount} setoran</td><td className="px-5 py-4"><StatusBadge value={row.weakCount > 0 ? "perlu_murajaah" : "lulus"}/></td></tr>)}{!rows.length && <tr><td colSpan={6}><EmptyState title="Belum ada data laporan" description="Tambahkan santri dan setoran untuk membentuk rekap laporan."/></td></tr>}</tbody></table></div></SectionCard><div className="mt-5 grid gap-4 sm:grid-cols-3"><div className="rounded-2xl border border-slate-200 bg-white p-5"><p className="text-xs font-bold uppercase tracking-wider text-slate-400">Total setoran</p><p className="mt-2 font-display text-3xl font-bold text-slate-900">{data.dashboard.stats.totalSubmissionCount}</p><p className="mt-1 text-xs text-slate-500">dalam cakupan laporan</p></div><div className="rounded-2xl border border-slate-200 bg-white p-5"><p className="text-xs font-bold uppercase tracking-wider text-slate-400">Setoran hari ini</p><p className="mt-2 font-display text-3xl font-bold text-emerald-700">{data.dashboard.stats.todayCount}</p><p className="mt-1 text-xs text-slate-500">aktivitas terbaru</p></div><div className="rounded-2xl border border-slate-200 bg-white p-5"><p className="text-xs font-bold uppercase tracking-wider text-slate-400">Nilai kolektif</p><p className="mt-2 font-display text-3xl font-bold text-amber-600">{data.dashboard.stats.averageScore || "—"}</p><p className="mt-1 text-xs text-slate-500">rata-rata seluruh setoran</p></div></div></>;
}
